#include<bits/stdc++.h>
using namespace std;
int dis[200010];
bool vis[200010];
vector<pair<int,int>> mp[200010];
void dijkstra(int st)
{
    memset(vis,0,sizeof(vis));
    memset(dis,0x3f,sizeof(dis));
    dis[st]=0;
    priority_queue<pair<int,int>> q;
    q.push(make_pair(0,st));
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=1;
        for(auto i:mp[t])
        {
            int v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
int main()
{
    int n,m,k;
    scanf("%d%d%d",&n,&m,&k);
    int s,t;
    scanf("%d%d",&s,&t);
    s++;
    t++;
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        u++;
        v++;
        for(int j=0;j<=k;j++)
        {
            mp[j*n+u].push_back(make_pair(j*n+v,w));
            mp[j*n+v].push_back(make_pair(j*n+u,w));
        }
        for(int j=0;j<k;j++)
        {
            mp[j*n+u].push_back(make_pair((j+1)*n+v,0));
            mp[j*n+v].push_back(make_pair((j+1)*n+u,0));
        }
    }
    dijkstra(s);
    int ans=INT_MAX;
    for(int i=0;i<=k;i++)
    {
        ans=min(ans,dis[i*n+t]);
    }
    printf("%d",ans);
    return 0;
}
